class Solution:
    def subarrayLCM(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        from math import gcd

        def lcm(a, b):
            return a * b // gcd(a, b)

        count = 0

        for i in range(len(nums)):
            current_lcm = 1
            for j in range(i, len(nums)):
                current_lcm = lcm(current_lcm, nums[j])

                if current_lcm == k:
                    count += 1
                elif current_lcm > k:
                    # LCM can only increase, stop if > k
                    break

        return count
